    enum OrderStatus {
        None,
        Pending,
        Shipped,
        Completed,
        Rejected,
        Cancelled
    }

    OrderStatus public status; //默认为None

    struct Order {
        address buyer;
        OrderStatus status;
    }

    Order[] public  orders;

    function add(Order memory order) external {
        orders.push(order);
    }

    function setStatus(OrderStatus newStatus) external {
        status = newStatus;
    }

    function getStatus() external view returns(OrderStatus){
       return status;
    }

    function reset() external {
        delete status;
    }
}

